tor Width'=>'Activar el ancho del editor','Experimental editor CSS for less excess margins in Gutenberg in an attempt to get a closer WYSIWYG editing experience.'=>'Editor experimental CSS para menos exceso de márgenes en Gutenberg en un intento de obtener una experiencia de edición WYSIWYG más cercana','False'=>'Falso','Fullwidth'=>'Ancho completo','Icon'=>'Ícono','Kadence Blocks'=>'Kadence Blocks','Kadence Blocks -  Gutenberg Page Builder Blocks'=>'Kadence Blocks - Gutenberg Page Builder Blocks','Kadence Blocks - Gutenberg Page Builder Blocks'=>'Kadence Blocks - Gutenberg Page Builder Blocks','Large'=>'Grande','Large Template'=>'Plantilla grande','Note: The current active themes "content_width" is set to:'=>'Nota: Los temas activos actualmente tienen `content_width` establecido en:','Page Default'=>'Página por defecto','Post default'=>'Entrada por defecto','Row Layout'=>'Diseño de la fila','Save Changes'=>'Guardar los cambios','Settings'=>'Ajustes','Small'=>'Pequeño','Small Template'=>'Plantilla pequeña','Spacer/Divider'=>'Espaciador/Divisor','Support'=>'Soporte','Tabs'=>'Pestañas','True'=>'Verdadero','https://www.kadencewp.com/product/kadence-gutenberg-blocks/'=>'https://www.kadencewp.com/product/kadence-gutenberg-blocks/','px'=>'px']];